@carver  like so?
```python
def encode_rpc_request(self, method, params):
        try:
            return to_bytes(text=json.dumps({
                "jsonrpc": "2.0",
                "method": method,
                "params": params or [],
                "id": next(self.request_counter),
            }))
        except TypeError:
            err_msg = ''
            for i, p in enumerate(params):
                try:
                    json.dumps(p)
                except Exception:
                    err_msg += ' ({},{});'.format(i, repr(p))
            msg = 'encode_rpc_request failure for method {} for invalid (index, parameter): '
            msg += err_msg.rstrip(';') + '.'
            raise TypeError(msg.format(method))
```

